"""04_heatmaps.py--------------NJ Literacy & COVID Economic Impact — District Heatmap ScriptProduces two choropleth heatmaps of NJ school district ELA proficiency,one for 2017-2018 (Pre-COVID baseline) and one for 2023-2024 (most recent),using the NJ Unified School Districts shapefile.Both maps share the same color scale so they are directly comparable.Districts with no NJSLA data (typically very small single-school districts)are shown in light gray.Output files saved to output/figures/:  fig3_heatmap_ela_2017_2018.png  fig4_heatmap_ela_2023_2024.pngUsage:  Must be run AFTER 01_clean_data.py.  python scripts/04_heatmaps.pyData requirements in data/raw/:  school_districts_shp/School_Districts_Unified.shp    Download from NJ Office of GIS:    https://njogis-newjersey.opendata.arcgis.com/  ela_by_district_year.csv produced by 01_clean_data.pyRequirements:  pip install pandas geopandas matplotlib mapclassify"""import osimport warningsimport numpy as npimport pandas as pdimport geopandas as gpdimport matplotlib.pyplot as pltimport matplotlib.colors as mcolorsimport matplotlib.patches as mpatchesfrom matplotlib.colorbar import ColorbarBasewarnings.filterwarnings("ignore")# ── Paths ────────────────────────────────────────────────────────────────────RAW_DIR    = os.path.join("data", "raw")PROC_DIR   = os.path.join("data", "processed")OUTPUT_DIR = os.path.join("output", "figures")os.makedirs(OUTPUT_DIR, exist_ok=True)SHP_PATH = os.path.join(RAW_DIR, "School_Districts___Unified_6015899820111362267",                         "School_Districts_Unified.shp")ELA_PATH = os.path.join(PROC_DIR, "ela_by_district_year.csv")# ── Map settings ─────────────────────────────────────────────────────────────YEARS_TO_MAP = ["2017-2018", "2023-2024", "2021-2022"]YEAR_LABELS  = {    "2017-2018": "2017–2018  (Pre-COVID Baseline)",    "2023-2024": "2023–2024  (Post-COVID Recovery)",    "2021-2022": "2021-2022  (Post-Covid)",}OUTPUT_NAMES = {    "2017-2018": "fig3_heatmap_ela_2017_2018.png",    "2023-2024": "fig4_heatmap_ela_2023_2024.png",    "2021-2022": "fig5_heatmap_ela_2021-2022.png",}# Shared proficiency scale — fixed so both maps are directly comparableVMIN, VMAX = 0, 100         # full 0–100% rangeNJ_GOAL    = 80             # state 2030 target# Color scale: dark red (0%) → yellow (~50%) → bright green (100%)# Red = below goal / low proficiency; green = at or above goalCMAP = mcolors.LinearSegmentedColormap.from_list(    "literacy",    [        (0.00, "#8B0000"),   # dark red       — very low        (0.30, "#CC3300"),   # red        (0.45, "#E87722"),   # orange        (0.55, "#F5C518"),   # yellow         — around 50%        (0.70, "#8BC34A"),   # yellow-green        (0.80, "#4CAF50"),   # green          — approaching goal        (1.00, "#1B5E20"),   # dark green     — at/above 80% goal    ],)# ════════════════════════════════════════════════════════════════════════════# Data loading & joining# ════════════════════════════════════════════════════════════════════════════def load_and_join(year: str) -> gpd.GeoDataFrame:    """    Load the shapefile, merge with ELA proficiency for the given school year,    and reproject to a standard display CRS.    Join key: NJDOE_ID_U in shapefile == county_code + '-' + district_code    in the ELA CSV (both zero-padded: e.g. '05-1170').    """    gdf = gpd.read_file(SHP_PATH)    ela = pd.read_csv(ELA_PATH, dtype={"county_code": str, "district_code": str})    # Build the same composite key used in the shapefile    ela["njdoe_id"] = (        ela["county_code"].str.zfill(2) + "-" +        ela["district_code"].str.zfill(4)    )    ela_year = ela[ela["school_year"] == year][        ["njdoe_id", "ela_proficiency_pct", "dfg", "district_name"]    ].drop_duplicates("njdoe_id")    merged = gdf.merge(ela_year, left_on="NJDOE_ID_U",                       right_on="njdoe_id", how="left")    # Reproject to Web Mercator for clean display    merged = merged.to_crs(epsg=3857)    return merged# ════════════════════════════════════════════════════════════════════════════# Map drawing# ════════════════════════════════════════════════════════════════════════════def draw_map(gdf: gpd.GeoDataFrame, year: str, out_path: str) -> None:    """    Draw a single choropleth heatmap for one school year and save to disk.    """    fig, ax = plt.subplots(figsize=(11, 13))    fig.patch.set_facecolor("#0f1117")    ax.set_facecolor("#0f1117")    # ── Districts WITH data ───────────────────────────────────────────────    has_data = gdf[gdf["ela_proficiency_pct"].notna()].copy()    no_data  = gdf[gdf["ela_proficiency_pct"].isna()].copy()    # Plot no-data districts first (gray base)    if not no_data.empty:        no_data.plot(            ax=ax,            color="#2a2a2a",            edgecolor="#444",            linewidth=0.3,            zorder=1,        )    # Plot proficiency choropleth    has_data.plot(        ax=ax,        column="ela_proficiency_pct",        cmap=CMAP,        vmin=VMIN,        vmax=VMAX,        edgecolor="#1a1a1a",        linewidth=0.25,        zorder=2,        legend=False,    )    # ── Colorbar ──────────────────────────────────────────────────────────    norm = mcolors.Normalize(vmin=VMIN, vmax=VMAX)    sm   = plt.cm.ScalarMappable(cmap=CMAP, norm=norm)    sm.set_array([])    cbar_ax = fig.add_axes([0.78, 0.18, 0.03, 0.55])    cbar_ax.set_facecolor("#0f1117")    cb = fig.colorbar(sm, cax=cbar_ax)    cb.ax.yaxis.set_tick_params(color="#AAAAAA", labelsize=8)    cb.outline.set_edgecolor("#444")    plt.setp(cb.ax.yaxis.get_ticklabels(), color="#AAAAAA")    cb.set_label("ELA Proficiency (%)", color="white", fontsize=9, labelpad=8)    # Mark the 80% goal on the colorbar    goal_frac = (NJ_GOAL - VMIN) / (VMAX - VMIN)    cbar_ax.axhline(goal_frac, color="#FFD700", linewidth=1.5, linestyle="--")    cbar_ax.text(1.35, goal_frac, "80%\ngoal",                 color="#FFD700", fontsize=7.5, va="center",                 transform=cbar_ax.transAxes)    # ── Summary statistics annotation ─────────────────────────────────────    vals  = has_data["ela_proficiency_pct"]    mean  = vals.mean()    below = (vals < NJ_GOAL).sum()    total = len(vals)    pct_below = below / total * 100    stats_text = (        f"Statewide Mean:  {mean:.1f}%\n"        f"Below 80% Goal:  {below} of {total} districts ({pct_below:.0f}%)"    )    ax.text(        0.02, 0.03, stats_text,        transform=ax.transAxes,        fontsize=8.5, color="#CCCCCC",        verticalalignment="bottom",        bbox=dict(boxstyle="round,pad=0.4", facecolor="#1a1a2e",                  edgecolor="#444", alpha=0.85),    )    # ── No-data legend entry ──────────────────────────────────────────────    if not no_data.empty:        gray_patch = mpatches.Patch(            facecolor="#2a2a2a", edgecolor="#555",            label=f"No NJSLA data ({len(no_data)} districts)"        )        ax.legend(            handles=[gray_patch],            loc="lower left", fontsize=7.5,            framealpha=0.7, facecolor="#1a1a2e",            edgecolor="#444", labelcolor="white",        )    # ── Title & labels ─────────────────────────────────────────────────────    ax.set_title(        f"NJ School District ELA Proficiency\n{YEAR_LABELS[year]}",        color="white", fontsize=14, fontweight="bold",        pad=14, loc="left",    )    fig.text(        0.13, 0.06,        "Source: NJ DOE School Performance Reports  |  "        "Shapefile: NJ Office of GIS\n"        "Color scale: red = low proficiency → green = at or above 80% state goal",        color="#666", fontsize=7.5, style="italic",    )    # ── Clean up axes ──────────────────────────────────────────────────────    ax.set_axis_off()    plt.tight_layout(rect=[0, 0.07, 0.78, 1])    fig.savefig(out_path, dpi=150, bbox_inches="tight",                facecolor=fig.get_facecolor())    plt.close()    print(f"  Saved: {out_path}")# ════════════════════════════════════════════════════════════════════════════# MAIN# ════════════════════════════════════════════════════════════════════════════def main():    print("=" * 62)    print("NJ Literacy & COVID Economic Impact — 04_heatmaps.py")    print("=" * 62)    # Validate inputs    for path, label in [(SHP_PATH, "Shapefile"), (ELA_PATH, "ELA CSV")]:        if not os.path.exists(path):            print(f"\n  Missing {label}: {path}")            if label == "Shapefile":                print("  Unzip School_Districts_Unified.zip into data/raw/school_districts_shp/")            else:                print("  Run 01_clean_data.py first.")            return    for year in YEARS_TO_MAP:        print(f"\n  Processing {year}...")        gdf      = load_and_join(year)        matched  = gdf["ela_proficiency_pct"].notna().sum()        total    = len(gdf)        mean_ela = gdf["ela_proficiency_pct"].mean()        print(f"    Districts with data : {matched}/{total}")        print(f"    Statewide mean ELA  : {mean_ela:.1f}%")        out_path = os.path.join(OUTPUT_DIR, OUTPUT_NAMES[year])        draw_map(gdf, year, out_path)    print("\n" + "=" * 62)    print("HEATMAPS COMPLETE")    print(f"Saved to: {OUTPUT_DIR}/")    print("=" * 62)if __name__ == "__main__":    main()